import{_ as t,o,c as a,a2 as i}from"./chunks/framework.Bk_3gXAz.js";const m=JSON.parse(`{"title":"mom-test","description":"Talk to customers without leading them using Mom Test rules: discuss their life not your idea, ask about specifics in the past, and talk less. Use when the user mentions \\"customer interviews\\", \\"validate my idea\\", \\"users say they want it but don't buy\\", \\"leading questions\\", or \\"The Mom Test\\". Covers commitment and advancement, avoiding compliments, and extracting signal from noise. For product-market fit, see jobs-to-be-done. For rapid prototype testing, see design-sprint.","frontmatter":{"title":"mom-test","name":"mom-test","description":"Talk to customers without leading them using Mom Test rules: discuss their life not your idea, ask about specifics in the past, and talk less. Use when the user mentions \\"customer interviews\\", \\"validate my idea\\", \\"users say they want it but don't buy\\", \\"leading questions\\", or \\"The Mom Test\\". Covers commitment and advancement, avoiding compliments, and extracting signal from noise. For product-market fit, see jobs-to-be-done. For rapid prototype testing, see design-sprint.","license":"MIT","metadata":{"author":"wondelai","version":"1.0.0"}},"headers":[],"relativePath":"skills/mom-test.md","filePath":"skills/mom-test.md"}`),n={name:"skills/mom-test.md"};function s(r,e,l,d,u,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="the-mom-test-framework" tabindex="-1">The Mom Test Framework <a class="header-anchor" href="#the-mom-test-framework" aria-label="Permalink to &quot;The Mom Test Framework&quot;">​</a></h1><p>Framework for having useful customer conversations that won&#39;t lead you astray. Based on a fundamental truth: everyone is lying to you -- not because they&#39;re malicious, but because you&#39;re asking the wrong questions. Your mom will tell you your idea is great because she loves you. Investors, friends, and even potential customers will do the same. The Mom Test provides rules for asking questions so good that even your mom can&#39;t lie to you.</p><h2 id="core-principle" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h2><p><strong>Good customer conversations are about their life, not your idea.</strong> The moment you mention what you&#39;re building, people switch from sharing truth to performing politeness. They tell you what you want to hear. The antidote is simple: talk about their problems, their lives, and their existing behavior instead of pitching your solution. Ask about specifics in the past, not hypotheticals about the future. And above all, talk less and listen more.</p><h2 id="scoring" tabindex="-1">Scoring <a class="header-anchor" href="#scoring" aria-label="Permalink to &quot;Scoring&quot;">​</a></h2><p><strong>Goal: 10/10.</strong> When reviewing or planning customer conversations, rate them 0-10 based on adherence to the principles below. A 10/10 means questions focus entirely on the customer&#39;s life and past behavior, with no leading, no pitching, and clear commitment signals; lower scores indicate gaps to address. Always provide the current score and specific improvements needed to reach 10/10.</p><h2 id="framework-sections" tabindex="-1">Framework Sections <a class="header-anchor" href="#framework-sections" aria-label="Permalink to &quot;Framework Sections&quot;">​</a></h2><h3 id="_1-the-mom-test-rules" tabindex="-1">1. The Mom Test Rules <a class="header-anchor" href="#_1-the-mom-test-rules" aria-label="Permalink to &quot;1. The Mom Test Rules&quot;">​</a></h3><p><strong>Core concept:</strong> Three simple rules that, when followed, make it impossible for even your most supportive loved ones to give you false validation. The rules shift conversations from opinion-gathering to fact-finding.</p><p><strong>Why it works:</strong> Opinions are worthless because people are unreliable predictors of their own future behavior. Past behavior is the only reliable data. By focusing on what people have actually done rather than what they say they would do, you extract facts that can genuinely inform product decisions.</p><p><strong>Key insights:</strong></p><ul><li>Rule 1: Talk about their life, not your idea -- never mention your solution until the end (if at all)</li><li>Rule 2: Ask about specifics in the past, not generics or hypotheticals about the future</li><li>Rule 3: Talk less, listen more -- aim for them to speak 80% of the time</li><li>A question fails the Mom Test if the answer is always &quot;yes&quot; regardless of whether the business will succeed</li><li>Good questions are ones that could potentially destroy your currently imagined business</li><li>You want facts and commitments, not compliments and opinions</li><li>The best learning happens when you shut up and let awkward silences do the work</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Application</th><th>Example</th></tr></thead><tbody><tr><td>Idea validation</td><td>Ask about the problem, never the solution</td><td>&quot;Tell me about the last time you tried to [problem area]&quot; instead of &quot;Would you use an app that does X?&quot;</td></tr><tr><td>Feature prioritization</td><td>Discover what people actually do vs. what they say</td><td>&quot;Walk me through how you handled this last week&quot; reveals real workflow</td></tr><tr><td>Pricing research</td><td>Anchor to existing spending behavior</td><td>&quot;What are you currently paying to solve this?&quot; instead of &quot;Would you pay $X?&quot;</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;Tell me about the last time you...&quot;</li><li>&quot;What happened next?&quot;</li><li>&quot;How are you dealing with that currently?&quot;</li><li>&quot;Can you walk me through your process?&quot;</li><li>&quot;What else have you tried?&quot;</li></ul><p><strong>Ethical boundary:</strong> Never weaponize someone&#39;s honest answers against them. The Mom Test earns trust by respecting people&#39;s time and honesty -- using vulnerability data to manipulate sales crosses the line.</p><p>See: <a href="./references/question-patterns">references/question-patterns.md</a></p><h3 id="_2-good-vs-bad-questions" tabindex="-1">2. Good vs Bad Questions <a class="header-anchor" href="#_2-good-vs-bad-questions" aria-label="Permalink to &quot;2. Good vs Bad Questions&quot;">​</a></h3><p><strong>Core concept:</strong> Most customer interview questions are fundamentally broken because they ask people to predict the future, evaluate hypothetical products, or confirm your assumptions. Good questions anchor in observable past behavior and extract concrete facts.</p><p><strong>Why it works:</strong> Humans are terrible at predicting their own behavior. Asking &quot;would you buy this?&quot; is like asking &quot;will you go to the gym next week?&quot; -- the answer is always yes, the follow-through is rarely there. Questions about what people have already done are reliable because behavior has already happened and can&#39;t be rationalized away.</p><p><strong>Key insights:</strong></p><ul><li>Bad: &quot;Do you think it&#39;s a good idea?&quot; -- always gets a yes</li><li>Bad: &quot;Would you buy a product that does X?&quot; -- hypothetical, meaningless</li><li>Bad: &quot;How much would you pay for X?&quot; -- people anchor to what you want to hear</li><li>Good: &quot;How are you dealing with this problem today?&quot; -- reveals actual behavior</li><li>Good: &quot;What have you tried before and why did you stop?&quot; -- reveals past decisions</li><li>Good: &quot;Where does the money come from for solutions like this?&quot; -- reveals real budgets</li><li>The scariest questions (ones you&#39;re afraid to ask) usually produce the most useful data</li><li>Ask questions that have the power to change what you&#39;re building</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Application</th><th>Example</th></tr></thead><tbody><tr><td>Problem validation</td><td>Confirm the problem exists and matters enough</td><td>&quot;When did this last come up? What did you do? What didn&#39;t work?&quot;</td></tr><tr><td>Market sizing</td><td>Understand if enough people have this problem</td><td>&quot;Who else in your company/industry deals with this? How do they handle it?&quot;</td></tr><tr><td>Competitive analysis</td><td>Discover real alternatives people already use</td><td>&quot;What tools/processes do you currently use for this?&quot;</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;What&#39;s the hardest part about [doing this thing]?&quot;</li><li>&quot;Why was that hard?&quot;</li><li>&quot;How often does this come up?&quot;</li><li>&quot;What does a perfect week look like for this workflow?&quot;</li><li>&quot;Talk me through the last time this happened&quot;</li></ul><p><strong>Ethical boundary:</strong> Never use leading or loaded questions that anchor the respondent toward your desired answer. Your job is to learn, not to sell.</p><p>See: <a href="./references/question-patterns">references/question-patterns.md</a></p><h3 id="_3-avoiding-compliments-and-opinions" tabindex="-1">3. Avoiding Compliments and Opinions <a class="header-anchor" href="#_3-avoiding-compliments-and-opinions" aria-label="Permalink to &quot;3. Avoiding Compliments and Opinions&quot;">​</a></h3><p><strong>Core concept:</strong> There are three types of bad data that feel like progress but actively mislead you: compliments (&quot;That&#39;s a great idea!&quot;), fluff (hypothetical statements, maybes, future promises), and ideas (feature requests disconnected from real problems). Learning to deflect these and dig for truth is the core skill of customer conversations.</p><p><strong>Why it works:</strong> Compliments are the fool&#39;s gold of customer development. They feel amazing -- &quot;Everyone loves our idea!&quot; -- but they contain zero information about whether anyone will actually pay for or use your product. Fluff and opinions give the illusion of validation without any concrete evidence. Only specifics about real past behavior and genuine commitments provide signal.</p><p><strong>Key insights:</strong></p><ul><li>Compliments: deflect immediately and get back to concrete facts (&quot;Thanks -- but let me understand how you&#39;re actually handling this today&quot;)</li><li>Fluff: generic claims (&quot;I usually,&quot; &quot;I always,&quot; &quot;I would never&quot;) are worthless without a specific instance</li><li>Ideas: when someone suggests a feature, dig into the motivation (&quot;That&#39;s interesting -- what&#39;s driving that? Tell me about the last time you needed something like that&quot;)</li><li>The &quot;would you buy this?&quot; trap: the answer is always yes because saying no feels rude</li><li>Fishing for compliments: unconsciously seeking validation (&quot;Don&#39;t you think this would be really useful?&quot;)</li><li>Symptoms of a bad conversation: you walk away feeling great but have no concrete facts or commitments</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Application</th><th>Example</th></tr></thead><tbody><tr><td>Post-demo feedback</td><td>Deflect &quot;this looks awesome&quot; to get actionable data</td><td>&quot;Thanks! What part of your current workflow would this actually replace?&quot;</td></tr><tr><td>Feature requests</td><td>Dig for the underlying job behind the request</td><td>&quot;Why do you want that? Can you show me the last time you needed it?&quot;</td></tr><tr><td>Investor conversations</td><td>Separate encouragement from real interest</td><td>Ask for intros to customers, not just &quot;great idea&quot; feedback</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;Thanks, but to make sure I&#39;m not wasting your time -- what does your current process look like?&quot;</li><li>&quot;Interesting. Can you tell me about a specific time that happened?&quot;</li><li>&quot;When you say you&#39;d &#39;definitely&#39; use this, what would you stop using?&quot;</li><li>&quot;That&#39;s a great feature idea -- what problem would it solve for you specifically?&quot;</li></ul><p><strong>Ethical boundary:</strong> Do not manipulate people into false commitments. Deflecting compliments is about getting to truth, not about pressuring someone into a sale.</p><p>See: <a href="./references/avoiding-bad-data">references/avoiding-bad-data.md</a></p><h3 id="_4-commitment-and-advancement" tabindex="-1">4. Commitment and Advancement <a class="header-anchor" href="#_4-commitment-and-advancement" aria-label="Permalink to &quot;4. Commitment and Advancement&quot;">​</a></h3><p><strong>Core concept:</strong> The currency of a customer conversation is not compliments -- it&#39;s commitment. Real interest shows up as willingness to invest something of value: time, reputation, or money. Every conversation should end with a clear &quot;advance&quot; (moving toward a sale/adoption) or a clear &quot;rejection&quot; (which is also valuable data). The worst outcome is a &quot;zombie lead&quot; -- someone who is polite but never commits.</p><p><strong>Why it works:</strong> Talk is cheap. When someone says &quot;I&#39;d definitely buy that,&quot; it costs them nothing. When someone offers to introduce you to their boss, puts a deposit down, or agrees to a pilot program, they&#39;re investing something real. The gap between what people say and what they do is the most dangerous trap in customer development. Commitment closes that gap.</p><p><strong>Key insights:</strong></p><ul><li>Commitment currencies: time (meeting, trial), reputation (intro, testimonial), money (deposit, pre-order, letter of intent)</li><li>Advancing: the conversation moves the relationship closer to a sale or adoption</li><li>Spinning wheels: pleasant conversations that never progress and produce zombie leads</li><li>Always know your &quot;ask&quot; before the meeting -- what&#39;s the minimum commitment that proves this is real?</li><li>A &quot;no&quot; is more valuable than a &quot;maybe&quot; -- at least you can learn from it and move on</li><li>First meeting ask: &quot;Would you be open to a 15-minute trial next week?&quot;</li><li>If they won&#39;t give you their time, they definitely won&#39;t give you their money</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Application</th><th>Example</th></tr></thead><tbody><tr><td>Early validation</td><td>Request a commitment that tests real interest</td><td>&quot;Can I follow up with a prototype next week for 15 minutes of your time?&quot;</td></tr><tr><td>B2B sales</td><td>Advance toward a decision-maker meeting</td><td>&quot;Could you introduce me to the person who handles the budget for this?&quot;</td></tr><tr><td>Pre-launch</td><td>Collect pre-orders or letters of intent</td><td>&quot;We&#39;re launching in 8 weeks -- would you like to be in the first cohort at 40% off?&quot;</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;What&#39;s the next step here?&quot;</li><li>&quot;Who else should I talk to about this?&quot;</li><li>&quot;Would you be willing to try a prototype next week?&quot;</li><li>&quot;Can I put you on the early access list?&quot;</li><li>&quot;If I built this, would you be willing to pilot it for 30 days?&quot;</li></ul><p><strong>Ethical boundary:</strong> Never pressure people into commitments they&#39;ll regret. The goal is to separate real interest from politeness, not to close a sale prematurely.</p><p>See: <a href="./references/commitment-advancement">references/commitment-advancement.md</a></p><h3 id="_5-finding-conversations" tabindex="-1">5. Finding Conversations <a class="header-anchor" href="#_5-finding-conversations" aria-label="Permalink to &quot;5. Finding Conversations&quot;">​</a></h3><p><strong>Core concept:</strong> You don&#39;t need a formal meeting to learn from customers. The best customer conversations happen casually -- at industry events, through warm intros, in online communities, or over coffee. Formal &quot;customer interview&quot; framing triggers performance mode where people tell you what they think you want to hear. Casual conversations produce more honest data.</p><p><strong>Why it works:</strong> When you say &quot;Can I interview you about your problems?&quot;, people put on armor. They become polished, guarded, and performative. When you say &quot;I&#39;m trying to learn about the industry -- can I buy you coffee?&quot;, people open up. The framing of the conversation determines the quality of the data you receive.</p><p><strong>Key insights:</strong></p><ul><li>Cold outreach: keep it short, lead with their expertise, don&#39;t pitch</li><li>Warm intros: the best source -- one good advisor can open dozens of doors</li><li>Industry events and meetups: go where your customers already gather</li><li>Online communities: participate genuinely before asking questions</li><li>Landing pages: use &quot;learn more&quot; signups to find engaged prospects</li><li>Keep it casual: &quot;I&#39;m trying to learn&quot; beats &quot;I&#39;m doing customer research&quot;</li><li>Vision/framing/weakness/pedestal/ask: a five-part structure for getting meetings</li><li>Advisors as a distribution channel: formalize relationships with well-connected people</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Application</th><th>Example</th></tr></thead><tbody><tr><td>Pre-idea exploration</td><td>Immerse yourself in the target community</td><td>Attend 3 industry events and have 20 casual conversations before writing a line of code</td></tr><tr><td>B2B prospecting</td><td>Use warm intros through advisors and investors</td><td>&quot;Our advisor [Name] suggested I talk to you about how you handle [problem area]&quot;</td></tr><tr><td>Consumer research</td><td>Intercept people at the point of behavior</td><td>Talk to people in line at the store, at the gym, at the coworking space</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;I&#39;m researching how [industry] handles [problem] -- could I learn from your experience over a 15-minute coffee?&quot;</li><li>&quot;[Mutual contact] suggested I talk to you because you know a lot about [area]&quot;</li><li>&quot;I&#39;m not trying to sell anything -- I&#39;m just trying to understand the space&quot;</li><li>&quot;I&#39;m thinking about starting something in [space] and want to make sure I&#39;m not delusional&quot;</li></ul><p><strong>Ethical boundary:</strong> Never disguise a sales call as a learning conversation. If you already have a product and are selling, be transparent. The Mom Test is for genuine learning, not for covert pitching.</p><p>See: <a href="./references/finding-conversations">references/finding-conversations.md</a></p><h3 id="_6-processing-and-learning" tabindex="-1">6. Processing and Learning <a class="header-anchor" href="#_6-processing-and-learning" aria-label="Permalink to &quot;6. Processing and Learning&quot;">​</a></h3><p><strong>Core concept:</strong> Customer conversations are only useful if you process them properly. Raw notes must be distilled into beliefs, updated regularly, and shared with your team. Without a system, you&#39;ll cherry-pick quotes that confirm your biases and ignore signals that challenge your assumptions.</p><p><strong>Why it works:</strong> Memory is unreliable and biased toward recent and emotionally charged information. Without structured note-taking and review, teams selectively remember the data that confirms what they already believe. Processing conversations as a team prevents any single person&#39;s bias from dominating the narrative.</p><p><strong>Key insights:</strong></p><ul><li>Take notes during or immediately after -- never rely on memory</li><li>Separate facts (what they said and did) from interpretations (what you think it means)</li><li>Share raw notes with your team, not filtered summaries</li><li>Update your three key beliefs: the problem, the customer segment, and the solution</li><li>Know when to stop talking and start building -- when conversations start repeating, you&#39;ve learned enough</li><li>Conversations are for learning, not for convincing yourself you&#39;re right</li><li>Use a simple spreadsheet: who, date, key quotes, facts, commitments, and belief changes</li></ul><p><strong>Product applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Application</th><th>Example</th></tr></thead><tbody><tr><td>Team alignment</td><td>Share notes in weekly standups to build shared understanding</td><td>Review 5 conversations per week as a team and update the belief board</td></tr><tr><td>Pivot decisions</td><td>Track when evidence contradicts your core beliefs</td><td>If 8 of 10 conversations reveal a different problem than expected, pivot</td></tr><tr><td>Feature validation</td><td>Count how many people mention a problem unprompted</td><td>A problem mentioned by 7 of 10 people is real; one mentioned by 1 of 10 might not be</td></tr></tbody></table><p><strong>Copy patterns:</strong></p><ul><li>&quot;Here are the exact quotes from this week&#39;s conversations&quot;</li><li>&quot;Our current belief is X -- here&#39;s what confirms it and what challenges it&quot;</li><li>&quot;We&#39;ve heard this from N of M people -- is that enough signal?&quot;</li><li>&quot;Time to stop talking and build -- conversations are repeating&quot;</li></ul><p><strong>Ethical boundary:</strong> Never misrepresent or selectively quote customer conversations to justify a predetermined conclusion. Honest processing means accepting uncomfortable truths.</p><p>See: <a href="./references/processing-learning">references/processing-learning.md</a></p><h2 id="common-mistakes" tabindex="-1">Common Mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common Mistakes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mistake</th><th>Why It Fails</th><th>Fix</th></tr></thead><tbody><tr><td>Pitching your idea instead of asking about their life</td><td>Triggers politeness, produces compliments instead of facts</td><td>Don&#39;t mention your idea until the very end, if at all</td></tr><tr><td>Asking &quot;would you buy this?&quot;</td><td>People always say yes to hypotheticals; it costs them nothing</td><td>Ask what they&#39;ve already done: &quot;How much are you spending on this now?&quot;</td></tr><tr><td>Accepting compliments as validation</td><td>&quot;Great idea!&quot; contains zero information about future behavior</td><td>Deflect immediately: &quot;Thanks -- but what are you doing about this today?&quot;</td></tr><tr><td>Talking too much</td><td>You learn nothing while talking; you learn everything while listening</td><td>Set a timer: they should talk 80% of the time or more</td></tr><tr><td>Not having a clear ask at the end</td><td>Produces zombie leads -- pleasant conversations that go nowhere</td><td>Know your advance before the meeting: trial, intro, pre-order</td></tr><tr><td>Running formal &quot;interview&quot; sessions</td><td>Triggers performance mode where people filter their answers</td><td>Keep it casual: coffee, hallway conversations, Slack DMs</td></tr><tr><td>Not processing notes as a team</td><td>Individual bias filters raw data into confirmation of existing beliefs</td><td>Share raw notes weekly and update shared beliefs together</td></tr></tbody></table><h2 id="quick-diagnostic" tabindex="-1">Quick Diagnostic <a class="header-anchor" href="#quick-diagnostic" aria-label="Permalink to &quot;Quick Diagnostic&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Question</th><th>If No</th><th>Action</th></tr></thead><tbody><tr><td>Did the conversation focus on their life and past behavior, not your idea?</td><td>You ran a pitch, not a Mom Test conversation</td><td>Redo with zero mention of your solution</td></tr><tr><td>Did you get concrete facts about what they&#39;ve already done?</td><td>You collected opinions and hypotheticals, which are meaningless</td><td>Ask about the last time they experienced the problem and what they did</td></tr><tr><td>Did they give you a commitment (time, reputation, or money)?</td><td>You may have a zombie lead -- polite but not interested</td><td>Ask for a specific next step: trial, intro, or pre-order</td></tr><tr><td>Did they do most of the talking?</td><td>You talked too much and learned too little</td><td>Practice silence; let awkward pauses work for you</td></tr><tr><td>Did you learn something that could change what you&#39;re building?</td><td>You asked safe questions that confirmed what you already believed</td><td>Ask the scary questions you&#39;ve been avoiding</td></tr><tr><td>Did you update your beliefs based on the conversation?</td><td>You&#39;re collecting data but not learning from it</td><td>Review notes with your team and update your problem/segment/solution beliefs</td></tr><tr><td>Can you summarize the key facts (not opinions) from the conversation?</td><td>You didn&#39;t take good notes or you&#39;re confusing opinions for facts</td><td>Separate facts from interpretations in your notes immediately after</td></tr></tbody></table><h2 id="reference-files" tabindex="-1">Reference Files <a class="header-anchor" href="#reference-files" aria-label="Permalink to &quot;Reference Files&quot;">​</a></h2><ul><li><a href="./references/question-patterns">question-patterns.md</a>: Good vs bad question examples, the three rules in depth, question formulation exercises</li><li><a href="./references/commitment-advancement">commitment-advancement.md</a>: Commitment currencies, advancing vs spinning wheels, how to push for commitment</li><li><a href="./references/avoiding-bad-data">avoiding-bad-data.md</a>: Compliments, fluff, ideas -- the three types of bad data and how to deflect them</li><li><a href="./references/finding-conversations">finding-conversations.md</a>: Where to find people, cold vs warm approaches, keeping conversations casual</li><li><a href="./references/processing-learning">processing-learning.md</a>: Note-taking, team sharing, updating beliefs, knowing when to stop talking</li><li><a href="./references/case-studies">case-studies.md</a>: Realistic scenarios showing Mom Test principles applied to SaaS, consumer, B2B, and marketplace contexts</li></ul><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><p>This skill is based on The Mom Test methodology developed by Rob Fitzpatrick. For the complete framework, examples, and deeper insights, read the original book:</p><ul><li><a href="https://www.amazon.com/Mom-Test-customers-business-everyone/dp/1492180742?tag=wondelai00-20" target="_blank" rel="noreferrer"><em>&quot;The Mom Test: How to Talk to Customers &amp; Learn if Your Business is a Good Idea When Everyone is Lying to You&quot;</em></a> by Rob Fitzpatrick</li></ul><h2 id="about-the-author" tabindex="-1">About the Author <a class="header-anchor" href="#about-the-author" aria-label="Permalink to &quot;About the Author&quot;">​</a></h2><p><strong>Rob Fitzpatrick</strong> is an entrepreneur, author, and educator who has founded multiple venture-backed startups and learned the hard way that most customer conversations are useless. After years of collecting misleading feedback and building products nobody wanted, he distilled the principles of effective customer conversations into <em>The Mom Test</em> (2013), which became one of the most recommended books in the startup ecosystem. The book has been translated into over 20 languages and is required reading at accelerators including Y Combinator, Techstars, and 500 Startups. Fitzpatrick has also written <em>The Workshop Survival Guide</em> and <em>Write Useful Books</em>, applying the same evidence-based approach to education and publishing. He teaches and advises startups across Europe and the US, and is known for his direct, practical style that prioritizes actionable frameworks over theory. He is based in the UK.</p>',84)])])}const p=t(n,[["render",s]]);export{m as __pageData,p as default};
